void VCmpTruF64Vop3::execute_impl(amdgpu::Wavefront &wf) {
  uint64_t exec = wf.exec();
  uint64_t vcc = vdst.read_scalar64(wf);
  for (uint32_t lane = 0; lane < wf.wf_size(); ++lane) {
    if (!(exec & (1ULL << lane)))
      continue;
    vcc |= (1ULL << lane);
  }
  vdst.write_scalar64(wf, vcc);
}

